const canvas = document.getElementById('gameCanvas');
const ctx = canvas.getContext('2d');
const player = { x: 50, y: 50, speed: 100 }; // speed in pixels per second
let lastFrameTime = performance.now();

function updatePlayerPosition(deltaTime) {
  const distance = player.speed * deltaTime;
  if (keys['ArrowUp']) player.y -= distance;
  if (keys['ArrowDown']) player.y += distance;
  if (keys['ArrowLeft']) player.x -= distance;
  if (keys['ArrowRight']) player.x += distance;
}

function validateDeltaTime(deltaTime) {
  return Math.min(Math.max(deltaTime, 0), 0.1); // Clamp deltaTime to prevent speed hacks
}

function gameLoop() {
  const currentTime = performance.now();
  let deltaTime = (currentTime - lastFrameTime) / 1000;
  deltaTime = validateDeltaTime(deltaTime);
  lastFrameTime = currentTime;

  updatePlayerPosition(deltaTime);
  render();
}

function render() {
  ctx.clearRect(0, 0, canvas.width, canvas.height);
  ctx.fillStyle = 'blue';
  ctx.fillRect(player.x, player.y, 20, 20);
}

const keys = {};
window.addEventListener('keydown', (e) => {
  if (['ArrowUp', 'ArrowDown', 'ArrowLeft', 'ArrowRight'].includes(e.key)) {
    keys[e.key] = true;
  }
});

window.addEventListener('keyup', (e) => {
  if (['ArrowUp', 'ArrowDown', 'ArrowLeft', 'ArrowRight'].includes(e.key)) {
    keys[e.key] = false;
  }
});

setInterval(gameLoop, 1000 / 60); // 60 FPS game loop